var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"분명 이 길이 맞는데…….","JPN":"この道で合ってるはずなんだけどな……","ENG":"I'm sure this is the right way...","TWN":"明明是這條路沒錯啊……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아닌가? 저기였나?","JPN":"違ったかな？　あっちだったっけ？","ENG":"Isn’t it? Maybe it was the other way?","TWN":"不對嗎？還是那裡？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"혹시 길을 잃어 버린 거야?","JPN":"もしかして道に迷ったの？","ENG":"We're not lost, are we?","TWN":"你該不會是迷路了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"자, 잠깐 헷갈렸을 뿐이야. 이 근처는 워낙 다 비슷비슷하게 생겨서 그래.","JPN":"ちょ、ちょっと混乱しただけだよ。この辺りは全部似たような形をしてるから。","ENG":"I-I just got a little confused. These hallways all look the same in this area.","TWN":"我…我只是暫時搞錯而已，因為這附近都長得很像嘛。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어쨌거나 경비가 덜한 뒷길인 건 확실하잖아.","JPN":"とにかく、警備が手薄な抜け道だってことは確かでしょ。","ENG":"Anyway, I'm sure it's in the back where security is low.","TWN":"起碼可以確定這裡沒什麼人看守吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그러게. 오면서 경비를 한 번도 안 마주쳤어.","JPN":"そうだね。ここに来る途中、一度も警備と出くわしていない。","ENG":"Yeah. I haven't seen a single guard around here.","TWN":"是沒錯，來的路上都沒遇到守衛。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"거 봐.","JPN":"ほら。","ENG":"See?","TWN":"你看吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"하지만, 이대로 헤맨다면 분명 경비를 왕창 마주치겠지.","JPN":"でも、このまま道に迷っているときっと警備とたくさん出くわすはず。","ENG":"But we'll eventually run into a lot if we keep getting lost like this.","TWN":"但再這樣繞下去，肯定會遇到一大堆守衛吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"끄응…….","JPN":"ぐうう……","ENG":"Ngh...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이봐, 샌님. 거의 다 온 것 같은데 계속 그렇게 조용히 있을래? ","JPN":"ちょっと、ナード。そろそろ着くけどずっと黙ってるつもり？ ","ENG":"Hey, dweeb. I think we're almost there, but are you really not going to say anything? ","TWN":"喂，先生，我們都快到咧，你打算繼續沉默不語嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"여기선 저쪽 길로 가야 돼.","JPN":"ここはあっち側に行くんだ。","ENG":"We need to head this way from here.","TWN":"從這裡要往那條路走才對。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그리고 두 번째 갈림길에서 좌측으로 틀어서 직진. 첫 번째 갈림길에서 우측에 있는 계단으로 내려간 다음 11시 방향에 있어.","JPN":"それから二つ目の分かれ道で左側に曲がって直進。一つ目の分かれ道で右側にある階段を降りた後、11時の方向にある。","ENG":"At the second fork we go left, then straight. Go down the stairs located to the right at the following crosswalk, and then follow the path northeast.","TWN":"接著在第二個岔路口左轉後直走，然後在第一個岔路口右邊的樓梯往下走，就會在11點鐘方向看到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네가 알고 있나 시험해 본 거였어. 가자.","JPN":"アンタが知ってるかどうか試してみただけだよ。行こう。","ENG":"I was just testing you to see if you were bluffing. C'mon, let's go.","TWN":"我是在考你到底知不知道，我們走吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"약속 지켜 주는 거지? 버리지 않기다?","JPN":"約束、守ってくれるんだよね？　置いてきぼりはなしだよ？","ENG":"So, you'll keep your promise then, right? I can tag along?","TWN":"你會遵守約定，不會扔下我吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래. 너 하는 거 봐서.","JPN":"わかった。アンタ次第だけどね。","ENG":"Yeah, whatever. We'll see.","TWN":"看你的表現再說吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"제대로 도착했네. 엔진실.","JPN":"ちゃんと着いたね。エンジンルーム。","ENG":"The engine room. We made it.","TWN":"真的找到引擎室咧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"봐, 내가 조금 더 잘 안다고 했지?","JPN":"ほら、僕の方がよく知ってるって言っただろ？","ENG":"See? I know this place a bit better than you, right?","TWN":"看吧，就說我知道的比你更詳細吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"갑자기 기고만장해지니까 꼴보기 싫네.","JPN":"いきなり威勢がよくなって憎たらしいったらないね。","ENG":"Ugh. You're so annoying when you get so smug.","TWN":"看你那副囂張的樣子，真討厭"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"따… 딱히 유세 부리려던 건 아니었어. 미안.","JPN":"べ……別に偉ぶるつもりはなかったんだ。ごめん。","ENG":"O-oh... I didn't mean to. Sorry...","TWN":"我…我不是故意要炫耀的，對不起。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시, 안에 누가 있을지도 몰라.","JPN":"ドロシー、中に誰かがいるかもしれないよ。","ENG":"Dorothy, someone could be in there.","TWN":"桃樂絲，裡面很可能會有人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"좋아, 바로 들어간다. 다들 마음 단단히 먹어.","JPN":"よし、すぐ入るよ。みんな、覚悟はいい？","ENG":"Okay, we're goin' in! Everyone, be prepared for anything...!","TWN":"好，進去吧，大家做好心理準備！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};